mapper.select:
SELECT DISTINCT a.id merchantsCode, a.merchants_name merchantsName, a.score score, a.lat lat, a.lng lng, a.address address, a.type type FROM app_b_user as a LEFT JOIN app_lable_details_review_tree as c ON a.id = c.user_b_id WHERE a.state = 1
AND city =#{city}
AND county =#{county}
AND a.type = 2 AND c.lable_id = 9 AND c.state = 1
AND a.lable_id like "%"#{lable,jdbcType=VARCHAR}"%"
AND merchants_level IS NOT NULL ORDER BY merchants_level
UNION ALL
SELECT id merchantsCode, `name` merchantsName, score, lat, lng, address, CONCAT('7') type FROM app_up_merchants where brand is null
AND citycode =#{city}
AND adcode =#{county}

SELECT a.id merchantsCode, a.merchants_name merchantsName, a.score score, a.lat lat, a.lng lng, a.address address, a.type type FROM app_b_user as a LEFT JOIN app_lable_details_review_tree as c ON a.id = c.user_b_id WHERE a.state = 1
AND city =#{city}
AND county =#{county}
AND a.type = 2 AND c.lable_id = 2 AND c.state = 1
UNION ALL
SELECT id merchantsCode, `name` merchantsName, score, lat, lng, address, CONCAT('7') type FROM app_up_merchants where brand is null
AND citycode =#{city}
AND adcode =#{county}

SELECT id merchantsCode, merchants_name merchantsName, score score, lat lat, lng lng, address address, type type FROM app_b_user WHERE state = 1
AND city =#{city}
AND county =#{county}
AND (type = 1 or type = 3)
UNION ALL
SELECT id merchantsCode, `name` merchantsName, score, lat, lng, address, CONCAT('7') type FROM app_up_merchants where brand is not null
AND citycode =#{city}
AND adcode =#{county}

SELECT a.id merchantsCode, merchants_name merchantsName, score score, lat lat, lng lng, address address, type type FROM app_b_user AS a LEFT JOIN app_merchants_brand AS b ON b.user_b_id = a.id WHERE a.state = 1
AND city =#{city}
AND county =#{county}
AND (type = 1 OR type = 3) AND b.brand_id = #{brand}
UNION ALL
SELECT id merchantsCode, `name` merchantsName, score, lat, lng, address, CONCAT('7') type FROM app_up_merchants where brand = #{brand}
AND citycode =#{city}
AND adcode =#{county}

SELECT a.id userBId,a.merchants_name merchantsName,b.end_time endTime,b.start_time startTime,a.address,type,score,lng,lat,huanxin_user_name huanxinUserName FROM app_b_user as a
	LEFT JOIN app_b_user_config as b on a.id = b.user_b_id
		WHERE a.id = #{userBId}

        SELECT a.id userBId,a.merchants_name merchantsName,a.address,a.score,(SELECT COUNT(1) FROM app_spray_paint_indent WHERE user_b_id = #{userBId}) sparyIndent,a.lng,a.lat,b.url imgUrl
         FROM app_b_user as a
	        LEFT JOIN app_merchants_info_banner as b ON a.id = b.user_b_id
		        WHERE a.id = #{userBId}
		        AND b.`index` = 1

                AND a.city = #{cityCode}


                ORDER BY score DESC

		        LIMIT #{pagesize},20;
